import math

# Output for dynamics = dq = [u_tail, d_theta_1, theta_1, dtheta_2, theta_2, dtheta_h, theta_h, x_t, y_t]
# Constants should be defined in the same order

class ChaplyginSleighModel:
    def __init__(self,const_vals,inp):
        """
        const_vals: flat list or tuple containing all constant parameters.
        """
