        # # For rotor 
        # c = 0.03                                   # length (m)
        # m_r = 0.1                                  # mass (kg)
        # I_r = m_r * 0.027**2                        # m.o.i (Kg/m^2) 
        # # Constant Rayleigh dissipation 
        # C_hx = 0.46
        # C_hy = 10
        # C_lx = 0
        # C_ly = 10
        # K_1 = 0.4           # stiffness (Nm/rad)
        # K_2 = 0.7           # stiffness (Nm/rad)

